import React, { useState, useEffect, useContext } from 'react';
import { useParams, Link } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import api from '../services/api';
import ProgressChart from '../components/ProgressChart';
import AIConfidenceIndicator from '../components/AIConfidenceIndicator';
import AIInsightCard from '../components/AIInsightCard';

const ProjectDetail = () => {
  const { id } = useParams();
  const { user } = useContext(AuthContext);
  const [project, setProject] = useState(null);
  const [sprints, setSprints] = useState([]);
  const [riskData, setRiskData] = useState(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchProjectData();
  }, [id]);

  const fetchProjectData = async () => {
    try {
      const [projectRes, sprintsRes] = await Promise.all([
        api.get(`/projects/${id}`),
        api.get(`/sprints?projectId=${id}`)
      ]);

      setProject(projectRes.data.project);
      setSprints(sprintsRes.data.sprints || []);
      setLoading(false);
    } catch (error) {
      console.error('Error fetching project data:', error);
      setLoading(false);
    }
  };

  const handleRiskAnalysis = async () => {
    setAnalyzing(true);
    try {
      const response = await api.get(`/ai/risk/${id}`);
      setRiskData(response.data);
      fetchProjectData(); // Refresh to get updated risk info
    } catch (error) {
      alert(error.response?.data?.message || 'Error analyzing risk');
    } finally {
      setAnalyzing(false);
    }
  };

  if (loading) {
    return (
      <div style={{ 
        display: 'flex', 
        flexDirection: 'column', 
        alignItems: 'center', 
        justifyContent: 'center', 
        minHeight: '60vh',
        gap: '20px'
      }}>
        <div style={{ 
          width: '60px', 
          height: '60px', 
          borderRadius: '16px', 
          background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          fontSize: '32px',
          boxShadow: '0 8px 16px rgba(99, 102, 241, 0.3)'
        }}>
          📁
        </div>
        <p style={{ color: '#64748b', fontSize: '16px', fontWeight: '600' }}>
          Loading project data...
        </p>
      </div>
    );
  }

  if (!project) {
    return <div className="alert alert-error">Project not found</div>;
  }

  const completedSprints = sprints.filter(s => s.status === 'Completed');
  const velocityData = completedSprints.map(sprint => ({
    label: sprint.name || `Sprint ${sprint._id.slice(-4)}`,
    value: sprint.actualVelocity || 0
  }));

  const getRiskInsights = () => {
    if (!riskData) return [];
    const insights = [];

    if (riskData.features) {
      if (riskData.features.missedDeadlines > 15) {
        insights.push({
          type: 'error',
          title: 'High Missed Deadlines',
          message: `${riskData.features.missedDeadlines.toFixed(1)}% of tasks have missed deadlines. Consider reviewing task estimates and deadlines.`,
          confidence: 85
        });
      }

      if (riskData.features.taskSpilloverRate > 30) {
        insights.push({
          type: 'warning',
          title: 'Task Spillover Detected',
          message: `${riskData.features.taskSpilloverRate.toFixed(1)}% of sprints experienced task spillover. Improve sprint planning accuracy.`,
          confidence: 80
        });
      }

      if (riskData.features.bugCount > 10) {
        insights.push({
          type: 'warning',
          title: 'High Bug Count',
          message: `${riskData.features.bugCount} bugs detected. Consider implementing better testing practices.`,
          confidence: 75
        });
      }
    }

    return insights;
  };

  return (
    <div className="fade-in">
      <div className="page-header">
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', flexWrap: 'wrap', gap: '16px' }}>
          <div style={{ flex: 1, minWidth: '300px' }}>
            <h1>{project.name}</h1>
            <p>{project.description || 'No description provided'}</p>
          </div>
          <div style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
            <Link to="/projects" className="btn btn-secondary">
              Back
            </Link>
            {user.role === 'PM' && (
              <button 
                onClick={handleRiskAnalysis} 
                className="btn btn-primary"
                disabled={analyzing}
              >
                {analyzing ? 'Analyzing...' : 'AI Risk Analysis'}
              </button>
            )}
          </div>
        </div>
      </div>

      {/* Project Stats Grid */}
      <div className="grid" style={{ marginBottom: '32px' }}>
        <div className="stat-card">
          <h3>👥 Team Members</h3>
          <div className="stat-value">{project.teamMembers?.length || 0}</div>
        </div>
        <div className="stat-card">
          <h3>🏃 Total Sprints</h3>
          <div className="stat-value" style={{ background: 'linear-gradient(135deg, #10b981 0%, #059669 100%)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>
            {sprints.length}
          </div>
        </div>
        <div className="stat-card">
          <h3>✅ Completed Sprints</h3>
          <div className="stat-value" style={{ background: 'linear-gradient(135deg, #3b82f6 0%, #2563eb 100%)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>
            {completedSprints.length}
          </div>
        </div>
        <div className="stat-card">
          <h3>⚠️ Risk Level</h3>
          <div style={{ fontSize: '32px', fontWeight: '800', marginTop: '8px' }}>
            <span className={`risk-${project.riskLevel?.toLowerCase() || 'low'}`}>
              {project.riskLevel || 'Low'}
            </span>
          </div>
          {project.riskScore > 0 && (
            <AIConfidenceIndicator 
              confidence={1 - (project.riskScore / 100)} 
              label="Risk Score"
            />
          )}
        </div>
      </div>

      {/* AI Risk Analysis */}
      {riskData && (
        <div className="card" style={{ marginBottom: '32px' }}>
          <div className="card-header">
            <span>🤖</span>
            AI Risk Analysis Results
          </div>

          <div style={{ marginBottom: '24px' }}>
            <div className={`alert alert-${riskData.riskLevel === 'High' ? 'error' : riskData.riskLevel === 'Medium' ? 'warning' : 'success'}`}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '12px' }}>
                <strong style={{ fontSize: '18px' }}>
                  Risk Level: {riskData.riskLevel}
                </strong>
                <span style={{ fontSize: '24px', fontWeight: '800' }}>
                  {riskData.riskScore}/100
                </span>
              </div>
              <p style={{ whiteSpace: 'pre-line', lineHeight: '1.8' }}>
                {riskData.explanation}
              </p>
            </div>
          </div>

          {riskData.features && (
            <div>
              <h4 style={{ marginBottom: '16px', color: '#1f2937' }}>Risk Factor Breakdown</h4>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '16px' }}>
                {riskData.features.missedDeadlines > 0 && (
                  <div style={{ padding: '16px', background: '#f9fafb', borderRadius: '8px' }}>
                    <div style={{ fontSize: '12px', color: '#6b7280', marginBottom: '8px' }}>MISSED DEADLINES</div>
                    <div style={{ fontSize: '24px', fontWeight: '800', color: '#ef4444' }}>
                      {riskData.features.missedDeadlines.toFixed(1)}%
                    </div>
                  </div>
                )}
                {riskData.features.taskSpilloverRate > 0 && (
                  <div style={{ padding: '16px', background: '#f9fafb', borderRadius: '8px' }}>
                    <div style={{ fontSize: '12px', color: '#6b7280', marginBottom: '8px' }}>TASK SPILLOVER</div>
                    <div style={{ fontSize: '24px', fontWeight: '800', color: '#f59e0b' }}>
                      {riskData.features.taskSpilloverRate.toFixed(1)}%
                    </div>
                  </div>
                )}
                {riskData.features.bugCount > 0 && (
                  <div style={{ padding: '16px', background: '#f9fafb', borderRadius: '8px' }}>
                    <div style={{ fontSize: '12px', color: '#6b7280', marginBottom: '8px' }}>BUG COUNT</div>
                    <div style={{ fontSize: '24px', fontWeight: '800', color: '#ef4444' }}>
                      {riskData.features.bugCount}
                    </div>
                  </div>
                )}
                {riskData.features.velocityFluctuation > 0 && (
                  <div style={{ padding: '16px', background: '#f9fafb', borderRadius: '8px' }}>
                    <div style={{ fontSize: '12px', color: '#6b7280', marginBottom: '8px' }}>VELOCITY FLUCTUATION</div>
                    <div style={{ fontSize: '24px', fontWeight: '800', color: '#f59e0b' }}>
                      {riskData.features.velocityFluctuation.toFixed(1)}%
                    </div>
                  </div>
                )}
              </div>
            </div>
          )}

          {getRiskInsights().length > 0 && (
            <div style={{ marginTop: '24px' }}>
              <h4 style={{ marginBottom: '16px', color: '#1f2937' }}>AI Recommendations</h4>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '16px' }}>
                {getRiskInsights().map((insight, idx) => (
                  <AIInsightCard key={idx} {...insight} />
                ))}
              </div>
            </div>
          )}
        </div>
      )}

      {/* Velocity Chart */}
      {velocityData.length > 0 && (
        <div className="card" style={{ marginBottom: '32px' }}>
          <div className="card-header">
            <span>📊</span>
            Sprint Velocity Trend
          </div>
          <ProgressChart data={velocityData} color="success" />
        </div>
      )}

      {/* Project Information */}
      <div className="card" style={{ marginBottom: '32px' }}>
        <div className="card-header">
          <span>ℹ️</span>
          Project Information
        </div>
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '16px' }}>
          <div>
            <strong style={{ color: '#6b7280', fontSize: '12px', textTransform: 'uppercase' }}>Created</strong>
            <p style={{ marginTop: '4px', fontSize: '16px', fontWeight: '600' }}>
              {new Date(project.createdAt).toLocaleDateString()}
            </p>
          </div>
          <div>
            <strong style={{ color: '#6b7280', fontSize: '12px', textTransform: 'uppercase' }}>Start Date</strong>
            <p style={{ marginTop: '4px', fontSize: '16px', fontWeight: '600' }}>
              {new Date(project.startDate).toLocaleDateString()}
            </p>
          </div>
          <div>
            <strong style={{ color: '#6b7280', fontSize: '12px', textTransform: 'uppercase' }}>Team Size</strong>
            <p style={{ marginTop: '4px', fontSize: '16px', fontWeight: '600' }}>
              {project.teamMembers?.length || 0} members
            </p>
          </div>
          {project.riskScore > 0 && (
            <div>
              <strong style={{ color: '#6b7280', fontSize: '12px', textTransform: 'uppercase' }}>Risk Score</strong>
              <p style={{ marginTop: '4px', fontSize: '16px', fontWeight: '600', color: project.riskScore > 60 ? '#ef4444' : project.riskScore > 30 ? '#f59e0b' : '#10b981' }}>
                {project.riskScore}/100
              </p>
            </div>
          )}
        </div>
      </div>

      {/* Sprints Table */}
      <div className="card">
        <div className="card-header">
          <span>🏃</span>
          Sprints ({sprints.length})
        </div>
        {sprints.length === 0 ? (
          <div style={{ textAlign: 'center', padding: '60px 40px' }}>
            <div style={{ 
              fontSize: '64px', 
              marginBottom: '24px',
              animation: 'pulse 2s ease-in-out infinite'
            }}>
              🏃
            </div>
            <h3 style={{ fontSize: '24px', marginBottom: '12px', color: '#1e293b', fontWeight: '800' }}>
              No Sprints Yet
            </h3>
            <p style={{ color: '#64748b', marginBottom: '24px', fontSize: '16px' }}>
              {user.role === 'PM' ? 'Get started by creating your first sprint with AI capacity prediction!' : 'No sprints available for this project yet.'}
            </p>
            {user.role === 'PM' && (
              <Link to="/sprints" className="btn btn-primary" style={{ fontSize: '16px', padding: '14px 28px' }}>
                + Create First Sprint
              </Link>
            )}
          </div>
        ) : (
          <div className="table-container" style={{ overflowX: 'auto' }}>
            <table className="table">
              <thead>
                <tr>
                  <th>Sprint Name</th>
                  <th>Status</th>
                  <th>Planned Velocity</th>
                  <th>Actual Velocity</th>
                  <th>AI Predicted</th>
                  <th>Health Score</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {sprints.map(sprint => (
                  <tr key={sprint._id}>
                    <td><strong>{sprint.name}</strong></td>
                    <td>
                      <span className={`badge badge-${sprint.status === 'Completed' ? 'success' : sprint.status === 'Active' ? 'info' : 'warning'}`}>
                        {sprint.status}
                      </span>
                    </td>
                    <td>{sprint.plannedVelocity} pts</td>
                    <td>
                      {sprint.actualVelocity ? (
                        <span style={{ fontWeight: '700' }}>{sprint.actualVelocity} pts</span>
                      ) : (
                        <span style={{ color: '#9ca3af' }}>-</span>
                      )}
                    </td>
                    <td>
                      {sprint.aiPredictedCapacity ? (
                        <span style={{ color: '#6366f1', fontWeight: '600' }}>
                          {sprint.aiPredictedCapacity} pts
                        </span>
                      ) : (
                        <span style={{ color: '#9ca3af' }}>-</span>
                      )}
                    </td>
                    <td>
                      {sprint.sprintHealthScore ? (
                        <div>
                          <div style={{ fontSize: '14px', fontWeight: '700', marginBottom: '4px' }}>
                            {sprint.sprintHealthScore}%
                          </div>
                          <div className="progress-bar" style={{ height: '6px' }}>
                            <div 
                              className="progress-fill" 
                              style={{ 
                                width: `${sprint.sprintHealthScore}%`,
                                background: sprint.sprintHealthScore >= 80 ? 'linear-gradient(90deg, #10b981 0%, #059669 100%)' :
                                            sprint.sprintHealthScore >= 60 ? 'linear-gradient(90deg, #f59e0b 0%, #d97706 100%)' :
                                            'linear-gradient(90deg, #ef4444 0%, #dc2626 100%)'
                              }}
                            />
                          </div>
                        </div>
                      ) : (
                        <span style={{ color: '#9ca3af' }}>-</span>
                      )}
                    </td>
                    <td>
                      <Link to={`/sprints/${sprint._id}`} className="btn btn-primary btn-sm">
                        View Details
                      </Link>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default ProjectDetail;
